class BlogEngine{constructor(){this.posts=[],this.filteredPosts=[],this.currentCategory="All Articles",this.postsPerPage=9,this.currentPage=1,this.blogFolder="./blogs/"}async init(){await this.loadBlogPosts(),this.setupEventListeners(),this.renderBlogPosts(),this.renderPagination()}async loadBlogPosts(){try{const e=await fetch("./blogs/blog-index.json");if(!e.ok)throw new Error("Index response was not ok");const t=await e.json(),n=(t.posts||[]).map(e=>fetch(`${this.blogFolder}${e}`).then(e=>{if(!e.ok)throw new Error("Post not found");return e.json()}).catch(t=>(console.error(`Error loading ${e}:`,t),null))),s=await Promise.all(n);this.posts=s.filter(e=>null!==e),this.posts.sort((e,t)=>new Date(t.date)-new Date(e.date)),this.filteredPosts=[...this.posts],console.log(`Loaded ${this.posts.length} blog posts`)}catch(e){console.error("Error loading blog index:",e),this.posts=[],this.filteredPosts=[]}}setupEventListeners(){document.querySelectorAll(".filter-btn").forEach(e=>{e.addEventListener("click",e=>{this.handleCategoryFilter(e.target)})})}handleCategoryFilter(e){document.querySelectorAll(".filter-btn").forEach(e=>e.classList.remove("active")),e.classList.add("active");const t=e.textContent.trim();this.currentCategory=t,this.filteredPosts="All Articles"===t?[...this.posts]:this.posts.filter(e=>e.category.toLowerCase()===t.toLowerCase()),this.currentPage=1,this.renderBlogPosts(),this.renderPagination()}renderBlogPosts(){const e=document.getElementById("blogGrid");if(!e)return;const t=(this.currentPage-1)*this.postsPerPage,n=t+this.postsPerPage,s=this.filteredPosts.slice(t,n);e.innerHTML="",s.forEach((t,n)=>{const s=this.createBlogCard(t,0===n&&1===this.currentPage);e.appendChild(s)}),0===s.length&&(e.innerHTML='<p style="text-align: center; grid-column: 1 / -1; padding: 5rem 0; color: #666; font-size: 0.95rem;">No blog posts found in this category.</p>')}createBlogCard(e,t=!1){const n=document.createElement("article");n.className="blog-card",t&&(n.style.gridColumn="span 1");let s="";if(e.image){const t=e.image.substring(0,e.image.lastIndexOf("."));s=`\n        <div style="width: 100%; height: 220px; overflow: hidden; border-bottom: 1px solid var(--color-border); margin-bottom: 1.5rem; background-color: var(--color-border); position: relative;">\n          <picture style="width: 100%; height: 100%; display: block;">\n            <source type="image/avif" srcset="./blogs_images/${t}.avif">\n            <source type="image/webp" srcset="./blogs_images/${t}.webp">\n            <img src="./blogs_images/${e.image}" \n                 alt="${e.title}" \n                 style="width: 100%; height: 100%; object-fit: cover; filter: grayscale(100%); transition: var(--transition-smooth);"\n                 class="blog-card-img"\n                 loading="lazy"\n                 onerror="this.style.display='none'; this.parentNode.style.display='none';">\n          </picture>\n        </div>\n      `}n.innerHTML=`\n      ${s}\n      <div style="display: flex; flex-direction: column; flex-grow: 1; justify-content: space-between; height: 100%;">\n        <div>\n          <span class="blog-card-category">${e.category}</span>\n          <h3 class="serif-font" style="font-size: 1.35rem; line-height: 1.3; margin-bottom: 1rem; font-weight: 500;">\n            <a href="${e.slug}.html">${e.title}</a>\n          </h3>\n          <p style="font-size: 0.9rem; color: #555555; margin-bottom: 1.5rem; line-height: 1.6;">${e.excerpt}</p>\n        </div>\n        <div class="blog-card-meta">\n          <span>${new Date(e.date).toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"})}</span>\n          <span>${e.readTime}</span>\n        </div>\n      </div>\n    `;const r=n.querySelector(".blog-card-img");return r&&(n.addEventListener("mouseenter",()=>{r.style.filter="grayscale(0%)",r.style.transform="scale(1.03)"}),n.addEventListener("mouseleave",()=>{r.style.filter="grayscale(100%)",r.style.transform="scale(1)"})),n}renderPagination(){const e=document.getElementById("pagination");if(!e)return;const t=Math.ceil(this.filteredPosts.length/this.postsPerPage);if(e.innerHTML="",!(t<=1))for(let n=1;n<=t;n++){const t=document.createElement("a");t.href="#",t.className="pagination-btn "+(n===this.currentPage?"active":""),t.textContent=n,t.style.cssText=`\n        display: inline-flex;\n        align-items: center;\n        justify-content: center;\n        width: 36px;\n        height: 36px;\n        border: 1px solid var(--color-border);\n        color: var(--color-text-dark);\n        font-weight: 500;\n        font-size: 0.85rem;\n        transition: var(--transition-fast);\n        background-color: ${n===this.currentPage?"var(--color-text-dark)":"transparent"};\n        color: ${n===this.currentPage?"var(--color-bg-cream)":"var(--color-text-dark)"};\n      `,t.addEventListener("click",e=>{e.preventDefault(),this.currentPage=n,this.renderBlogPosts(),this.renderPagination(),window.scrollTo({top:0,behavior:"smooth"})}),e.appendChild(t)}}}document.addEventListener("DOMContentLoaded",()=>{(new BlogEngine).init()});